UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"title":"Mislabeled Units","description":"A mislabeled unit reaching the wrong patient — a single clerical error with life-threatening consequences and no easy path to recovery."},{"title":"Expired Components","description":"Expired components missed because inventory tracking was manual, wasting precious donations and exposing patients to risk."},{"title":"Paper-Based Donor History","description":"A donor turned away — or worse, cleared in error — because eligibility history was stored on paper and never reconciled."},{"title":"Unstructured Reaction Reporting","description":"A transfusion reaction with no structured reporting pathway, no investigation workflow, and no data trail for hemovigilance."},{"title":"Audit Gaps","description":"A regulatory audit revealing gaps in chain-of-custody documentation — exactly the gaps that erode trust and put licensure at risk."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'blood-bank-and-donor-management' AND ps.data->>'section_name' = 'The Problem';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"icon":"UserCheck","title":"Donor Registration & Eligibility Screening","description":"Build comprehensive donor profiles with full medical history, travel records, medication flags, and deferral tracking. Automated eligibility checks against configurable screening criteria ensure no ineligible donor proceeds to collection. Permanent and temporary deferrals are logged and enforced system-wide."},{"icon":"Droplets","title":"Collection & Component Processing","description":"Record whole blood and apheresis collections with full lot traceability. Document component preparation — packed red cells, platelets, fresh frozen plasma, cryoprecipitate — with processing timestamps, technologist assignments, and quality checks at every step."},{"icon":"FlaskConical","title":"Blood Group Serology & Testing","description":"Manage ABO and Rh typing, antibody screening, and infectious disease testing workflows. Link laboratory results directly to unit records. Units with pending or failed test results are automatically quarantined and blocked from issue."},{"icon":"TestTube2","title":"Crossmatch & Compatibility Testing","description":"Run electronic or serological crossmatch workflows with built-in compatibility logic. The system flags incompatible pairings before issue, providing an additional patient safety checkpoint that never sleeps."},{"icon":"Boxes","title":"Inventory Management & Expiry Alerts","description":"Maintain real-time visibility of every unit across all storage locations — refrigerators, freezers, and satellite stores. Automated expiry alerts surface aging inventory days in advance, giving your team time to act before wastage occurs. FIFO issue logic is enforced by default."},{"icon":"Activity","title":"Transfusion Reaction Reporting & Hemovigilance","description":"When a transfusion reaction occurs, clinicians can log it directly in the system. The blood bank receives an immediate notification, triggering a structured investigation workflow. All reaction data feeds into your hemovigilance reporting module for regulatory submission and trend analysis."},{"icon":"Tag","title":"Regulatory-Compliant Labeling & Chain of Custody","description":"Every unit carries a compliant ISBT 128 label. Every movement — from collection through processing, storage, issue, and transfusion — is logged with user, timestamp, and location. Your audit trail is always complete, always current."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'blood-bank-and-donor-management' AND ps.data->>'section_name' = 'The Platform';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"icon":"UserCheck","title":"Donor Arrives","description":"The system retrieves the donor''s full history, runs automated eligibility checks, and either clears them for collection or flags the appropriate deferral reason — all before a needle is placed."},{"icon":"Droplets","title":"Unit Collected & Processed","description":"Collection details are recorded in real time. Components are processed and entered into inventory with full traceability. Testing requests are sent automatically to the laboratory."},{"icon":"FlaskConical","title":"Testing & Quarantine","description":"Units remain in quarantine until all required test results are received and validated. Reactive or incomplete results trigger automatic holds that cannot be overridden without authorization."},{"icon":"TestTube2","title":"Crossmatch & Issue","description":"A transfusion request arrives from the ward. The system performs compatibility checks, confirms crossmatch results, and issues the unit with a complete handover record."},{"icon":"HeartPulse","title":"Transfusion & Follow-up","description":"Transfusion is documented at the bedside. Any adverse events are reported through the integrated hemovigilance pathway. The complete unit lifecycle is archived for audit and regulatory review."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'blood-bank-and-donor-management' AND ps.data->>'section_name' = 'Patient Journey';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"value":"34%","label":"Average reduction in blood component wastage"},{"value":"100%","label":"Chain-of-custody documentation on every unit issued"},{"value":"60%","label":"Faster regulatory audit preparation with automated compliance reports"},{"value":"99.9%","label":"Unit traceability from collection to transfusion"}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'blood-bank-and-donor-management' AND ps.data->>'section_name' = 'Outcomes';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"q":"How does the system prevent incompatible blood from being issued?","a":"Compatibility logic is embedded in the issue workflow. Before any unit can be issued for transfusion, the system validates ABO and Rh compatibility and confirms crossmatch results. An incompatible pairing cannot proceed without a documented clinical override from an authorized user."},{"q":"Can the system handle both whole blood and apheresis collections?","a":"Yes. Both collection types are fully supported with separate workflow paths, component processing steps, and labeling requirements."},{"q":"What happens if a unit fails infectious disease testing?","a":"The unit is automatically placed under a system-enforced quarantine. It cannot be issued or moved to available inventory until the hold is reviewed and resolved by an authorized staff member. A complete record of the event is logged."},{"q":"Does the system support lookback and recall procedures?","a":"Yes. If a donor is later found to be reactive on a previous or subsequent donation, the system can trace all prior donations from that donor and initiate a structured lookback notification workflow."},{"q":"How does hemovigilance reporting work?","a":"Adverse transfusion events are logged directly by clinical staff. The blood bank is notified immediately. The system guides investigators through a structured root cause analysis and formats the completed report for submission to national or regional hemovigilance authorities."},{"q":"Is the system compliant with international blood banking standards?","a":"Yes. Secreta Blood Bank is designed to support compliance with AABB standards, EU Blood Directive requirements, FDA 21 CFR Part 11, and ISO 15189. Specific compliance configurations are available by region."},{"q":"How long does implementation take?","a":"Most blood banks complete full implementation in 3 to 6 weeks. Complex multi-site deployments with multiple HIS integrations may require additional time. A dedicated implementation specialist is assigned to every account."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'blood-bank-and-donor-management' AND ps.data->>'section_name' = 'FAQ';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"name":"AABB Accredited"},{"name":"FDA 21 CFR Part 11 Compliance"},{"name":"ICCBBA ISBT 128"},{"name":"ISO 15189 Accreditation"}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'blood-bank-and-donor-management' AND ps.data->>'section_name' = 'Integrations';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"title":"Prescribing Without Allergy Awareness","description":"A physician prescribes a drug without knowing the patient is allergic. Cross-reactive drug families are missed, and the patient is exposed to a preventable adverse reaction."},{"title":"Outdated Paper MARs","description":"A nurse administers the wrong dose because the paper MAR was updated after she printed it. What she holds in her hand is already out of date — and the patient pays the price."},{"title":"Missed Drug Interactions","description":"A pharmacist misses a dangerous interaction because two prescribers are using separate systems. The warning never fires, and a harmful combination reaches the patient."},{"title":"Unaccounted Controlled Substances","description":"A controlled substance goes unaccounted for because reconciliation is done manually at end of shift. Paper logs are incomplete, and diversion goes undetected."},{"title":"Weight-Based Dosing Errors","description":"A child receives an adult dose because weight-based calculation was done on a pocket calculator. A decimal place error, a unit conversion mistake — both can be fatal in pediatric care."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'healthcare-medication-dosage' AND ps.data->>'section_name' = 'The Problem';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"icon":"Stethoscope","title":"Electronic Prescribing with Clinical Decision Support","description":"Physicians prescribe digitally with real-time clinical decision support running in the background. Drug-drug interaction checks, allergy cross-referencing, duplicate therapy alerts, and contraindication warnings fire at the point of prescribing — before the order is placed, not after. Alerts are tiered by severity so clinicians see what matters without alert fatigue."},{"icon":"Pill","title":"Weight- and Age-Based Dosage Calculation Engine","description":"For pediatric, neonatal, and renally impaired patients, dosing errors are most dangerous and most common. Our built-in calculation engine pulls the patient''s current weight, age, and renal function from the clinical record and computes the correct dose range automatically. Prescribers see the recommended dose alongside safe minimum and maximum thresholds — every time."},{"icon":"ClipboardCheck","title":"Pharmacy Order Verification & Dispensing Queues","description":"Every electronic prescription lands directly in the pharmacy queue. Pharmacists review, clinically verify, and approve orders from a single organized screen — with patient history, current medication list, and interaction summaries always visible. Dispensing labels are generated automatically. Priority and urgent orders are surfaced to the top of the queue."},{"icon":"ScanLine","title":"Medication Administration Records with Barcode Scanning","description":"Nurses access a live, always-current eMAR at the bedside. Before administering any medication, they scan the patient wristband and the medication barcode. The system confirms the five rights — right patient, right drug, right dose, right route, right time — and flags any mismatch before administration occurs. Every administration is timestamped and logged automatically."},{"icon":"Lock","title":"Controlled Substance Tracking & Reconciliation","description":"Track every controlled substance from receipt to administration to waste. Tamper-evident digital logs record who accessed what, when, and how much was used or discarded. End-of-shift reconciliation is guided by the system, with discrepancy alerts escalating automatically to pharmacy supervisors. Diversion detection logic flags statistical anomalies for review."},{"icon":"Boxes","title":"Real-Time Pharmacy Inventory & Stock Visibility","description":"Pharmacists and ward managers see live stock levels across every dispensing location — central pharmacy, satellite pharmacies, automated dispensing cabinets, and ward stocks. Low-stock alerts trigger reorder workflows before shortages occur. Expiry tracking prevents expired medications from reaching patients."},{"icon":"RefreshCcw","title":"Medication Reconciliation at Care Transitions","description":"When a patient is admitted, transferred, or discharged, the system generates a complete reconciliation view — comparing home medications, inpatient orders, and discharge prescriptions side by side. Clinicians can identify, resolve, and document discrepancies in a structured workflow that reduces post-discharge adverse drug events."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'healthcare-medication-dosage' AND ps.data->>'section_name' = 'The Platform';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"icon":"FileText","title":"Prescribe","description":"The physician opens the patient record and enters a medication order. Clinical decision support checks for allergies, interactions, and dose appropriateness in real time. The order is placed only when it is safe to proceed."},{"icon":"ClipboardCheck","title":"Verify","description":"The prescription arrives instantly in the pharmacy queue. The pharmacist reviews the order in clinical context, approves it, and prepares the medication. Dispensing labels are printed automatically with all required identifiers."},{"icon":"Boxes","title":"Dispense","description":"The medication is dispensed from the correct location — central pharmacy, automated cabinet, or ward stock — with every movement logged against the patient order. Controlled substances require dual verification."},{"icon":"Syringe","title":"Administer","description":"The nurse scans the patient wristband and the medication barcode at the bedside. The system confirms a match against the live eMAR and gives a green light for administration. Any mismatch stops the process and triggers an alert."},{"icon":"FileCheck","title":"Document & Review","description":"Administration is recorded automatically. Missed doses, refusals, and partial doses are flagged for clinical review. Pharmacists and physicians see the complete medication administration history in real time."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'healthcare-medication-dosage' AND ps.data->>'section_name' = 'Patient Journey';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"value":"87%","label":"Reduction in medication administration errors after eMAR and barcode scanning go-live"},{"value":"100%","label":"Of controlled substance transactions logged with full audit trail"},{"value":"92%","label":"Of drug interaction alerts resolved at the prescribing stage — before the order is placed"},{"value":"40%","label":"Reduction in time spent on end-of-shift controlled substance reconciliation"},{"value":"3×","label":"Faster pharmacy order processing with digital queues and automated label generation"},{"value":"0","label":"Missed allergy alerts reported across all client sites post-implementation"}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'healthcare-medication-dosage' AND ps.data->>'section_name' = 'Outcomes';
UPDATE public.page_sections ps SET data = ps.data || '{"items":[{"q":"How does the system handle drug allergy checking?","a":"Allergy information is pulled directly from the patient''s clinical record. When a prescriber selects a medication, the system cross-references it against the full allergy list — including cross-reactive drug families — and displays a graded alert if any match is found. The prescriber must document a clinical justification to proceed past a high-severity alert."},{"q":"Can clinical decision support rules be customized?","a":"Yes. Your pharmacy and clinical informatics team can configure interaction thresholds, alert severity tiers, custom dosing protocols, and formulary restrictions. Customization does not require vendor involvement after initial setup."},{"q":"Does the system work with automated dispensing cabinets?","a":"Yes. Secreta integrates with leading ADC systems including Omnicell and Pyxis. Dispensing cabinet transactions sync automatically with the patient medication record and pharmacy inventory in real time."},{"q":"How does the pediatric dosing engine get patient weight?","a":"Weight is pulled automatically from the patient''s clinical record at the time of prescribing. If no current weight is recorded, the system prompts the prescriber to enter or confirm one before the dose calculation is displayed. Manual override is available with mandatory documentation."},{"q":"What happens if a nurse scans a wrong medication at the bedside?","a":"The barcode scan triggers an immediate mismatch alert on the eMAR screen. The administration is blocked and the nurse is shown what the correct medication should be. The event is logged automatically for pharmacy and clinical review."},{"q":"How is controlled substance diversion detected?","a":"The system tracks statistical patterns in controlled substance access and waste across users, shifts, and locations. When a user''s behavior deviates significantly from peer benchmarks — for example, consistently higher waste rates or access outside normal patterns — a confidential alert is generated for the pharmacy director."},{"q":"How long does implementation take?","a":"Most hospitals complete full implementation in 4 to 8 weeks. Complex multi-site deployments with multiple HIS integrations may require additional time. A dedicated implementation specialist is assigned to every account, and training is delivered on-site and virtually."}]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'healthcare-medication-dosage' AND ps.data->>'section_name' = 'The Platform';
UPDATE public.page_sections ps SET data = ps.data || '{"tags":["Epic","Cerner","Meditech","Omnicell","Pyxis","BD Rowa","Kirby Lester","HL7 v2 & FHIR","NCPDP SCRIPT","GS1 Barcodes","REST API","CPOE & eMAR Standards"]}'::jsonb FROM public.pages p WHERE ps.page_id = p.id AND p.slug = 'healthcare-medication-dosage' AND ps.data->>'section_name' = 'Integrations';